# In production, use a real database. This is for demonstration only.
USERS_DB = {}
SESSIONS_DB = {}

# Rate limiting storage: {ip: [(timestamp, ...), ...]}
LOGIN_ATTEMPTS = {}
MAX_LOGIN_ATTEMPTS = 5
LOGIN_ATTEMPT_WINDOW = 300  # 5 minutes


def hash_password(password, salt=None):
    """Hash a password with a salt using SHA-256 (use bcrypt/argon2 in production)."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return salt, hashed.hex()


def verify_password(password, salt, stored_hash):
    """Verify a password against a stored hash."""
    _, computed_hash = hash_password(password, salt)
    return secrets.compare_digest(computed_hash, stored_hash)


def validate_username(username):
    """Validate username to prevent injection and ensure reasonable format."""
    if not username or not isinstance(username, str):
        return False
    if len(username) < 3 or len(username) > 64:
        return False
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return False
    return True


def validate_password(password):
    """Validate password meets minimum requirements."""
    if not password or not isinstance(password, str):
        return False
    if len(password) < 8 or len(password) > 128:
        return False
    return True


def is_rate_limited(ip):
    """Check if an IP address is rate limited for login attempts."""
    now = time.time()
    if ip in LOGIN_ATTEMPTS:
        # Clean old attempts
        LOGIN_ATTEMPTS[ip] = [t for t in LOGIN_ATTEMPTS[ip] if now - t < LOGIN_ATTEMPT_WINDOW]
        if len(LOGIN_ATTEMPTS[ip]) >= MAX_LOGIN_ATTEMPTS:
            return True
    return False


def record_login_attempt(ip):
    """Record a failed login attempt for rate limiting."""
    now = time.time()
    if ip not in LOGIN_ATTEMPTS:
        LOGIN_ATTEMPTS[ip] = []
    LOGIN_ATTEMPTS[ip].append(now)


def clear_login_attempts(ip):
    """Clear login attempts after successful login."""
    if ip in LOGIN_ATTEMPTS:
        del LOGIN_ATTEMPTS[ip]


def create_session(username):
    """Create a new session for a user."""
    session_id = secrets.token_hex(32)
    SESSIONS_DB[session_id] = {
        'username': username,
        'created_at': time.time(),
        'last_active': time.time(),
    }
    return session_id


def get_session(session_id):
    """Retrieve and validate a session."""
    if not session_id or not isinstance(session_id, str):
        return None
    sess = SESSIONS_DB.get(session_id)
    if sess is None:
        return None
    # Check session expiry
    if time.time() - sess['created_at'] > app.config['PERMANENT_SESSION_LIFETIME']:
        destroy_session(session_id)
        return None
    # Update last active time
    sess['last_active'] = time.time()
    return sess


def destroy_session(session_id):
    """Destroy a session."""
    if session_id in SESSIONS_DB:
        del SESSIONS_DB[session_id]


def login_required(f):
    """Decorator to require login for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_id = session.get('session_id')
        sess = get_session(session_id)
        if sess is None:
            session.clear()
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def get_current_user():
    """Get the current logged-in user's username."""
    session_id = session.get('session_id')
    sess = get_session(session_id)
    if sess:
        return sess['username']
    return None


def escape_html(text):
    """Escape HTML to prevent XSS."""
    if not isinstance(text, str):
        return ''
    return (text
            .replace('&', '&amp;')
            .replace('<', '&lt;')
            .replace('>', '&gt;')
            .replace('"', '&quot;')
            .replace("'", '&#x27;'))


