@app.route('/logout', methods=['POST'])
def logout():
    """User logout."""
    if not validate_csrf_token():
        abort(403)

    session_id = session.get('session_id')
    if session_id:
        destroy_session(session_id)

    session.clear()
    return redirect(url_for('login'))


